import React, { useState } from 'react';
import SignUp from './SignUp';   // Correct import
import SignIn from './SignIn';   // Correct import

function App() {
  const [token, setToken] = useState(null);

  return (
    <div>
      <h1>Sports Stats App</h1>
      {!token ? (
        <div>
          <SignUp />
          <SignIn setToken={setToken} />
        </div>
      ) : (
        <div>Welcome! You are logged in with a token: {token}</div>
      )}
    </div>
  );
}

export default App;
